#include "custom_assets.h"
#include "../libc.h"

static int name_eq(const char *a, const char *b) {
    return a && b && k_strcmp(a, b) == 0;
}

static int title_has(const char *title, const char *needle) {
    return title && needle && k_strstr(title, needle) != 0;
}

void ui_draw_bitmap_scaled(const ui_bitmap_t *bmp, int x, int y, int w, int h) {
    if (!bmp || !bmp->pixels || w <= 0 || h <= 0) return;
    for (int py = 0; py < h; py++) {
        int sy = (py * bmp->h) / h;
        for (int px = 0; px < w; px++) {
            int sx = (px * bmp->w) / w;
            uint32_t src = bmp->pixels[sy * bmp->w + sx];
            uint8_t a = (uint8_t)COLOR_A(src);
            if (!a) continue;
            color_t rgb = RGB(COLOR_R(src), COLOR_G(src), COLOR_B(src));
            int dx = x + px;
            int dy = y + py;
            if (a == 255) vbe_put_pixel(dx, dy, rgb);
            else vbe_put_pixel(dx, dy, blend_color(rgb, vbe_get_pixel(dx, dy), a));
        }
    }
}

