const ui_bitmap_t *ui_bitmap_for_name(const char *name) {
    if (name_eq(name, "Calculatrice")) return &calculator_bmp;
    if (name_eq(name, "Parametres") || name_eq(name, "Paramètres")) return &settings_bmp;
    if (name_eq(name, "Horloge")) return &clock_bmp;
    if (name_eq(name, "Fichiers")) return &files_bmp;
    if (name_eq(name, "Editeur") || name_eq(name, "Éditeur")) return &editor_bmp;
    if (name_eq(name, "Terminal")) return &terminal_bmp;
    if (name_eq(name, "Navigateur") || name_eq(name, "Navigateur Web") || name_eq(name, "Web")) return &browser_bmp;
    if (name_eq(name, "Start") || name_eq(name, "Power")) return &start_bmp;
    if (name_eq(name, "Centre Système") || name_eq(name, "Centre Systeme") || name_eq(name, "System Monitor")) return &system_bmp;
    if (name_eq(name, "Tableau de bord")) return &hub_bmp;
    if (name_eq(name, "Commandes")) return &symera_bmp;
    if (name_eq(name, "Notes")) return &notes_bmp;
    if (name_eq(name, "Userspace") || name_eq(name, "Centre userspace")) return &userspace_bmp;
    if (name_eq(name, "Installer")) return &installer_bmp;
    if (name_eq(name, "Tutoriel") || name_eq(name, "Guide du bureau")) return &tutorial_bmp;
    if (name_eq(name, "Applications")) return &store_bmp;
    if (name_eq(name, "A propos") || name_eq(name, "À propos") || name_eq(name, "À propos du système")) return &about_bmp;
    return 0;
}

const ui_bitmap_t *ui_bitmap_for_window_title(const char *title) {
    if (!title) return 0;
    if (title_has(title, "Calculatrice")) return &calculator_bmp;
    if (title_has(title, "Param") || title_has(title, "Réglages") || title_has(title, "Settings")) return &settings_bmp;
    if (title_has(title, "Horloge")) return &clock_bmp;
    if (title_has(title, "Fichiers")) return &files_bmp;
    if (title_has(title, "Sans titre") || title_has(title, "Éditeur") || title_has(title, "Editeur")) return &editor_bmp;
    if (title_has(title, "Terminal")) return &terminal_bmp;
    if (title_has(title, "Navigateur") || title_has(title, "Browser") || name_eq(title, "Web")) return &browser_bmp;
    if (title_has(title, "System") || title_has(title, "Système")) return &system_bmp;
    if (title_has(title, "Tableau de bord")) return &hub_bmp;
    if (title_has(title, "Commandes")) return &symera_bmp;
    if (title_has(title, "Notes")) return &notes_bmp;
    if (title_has(title, "Userspace")) return &userspace_bmp;
    if (title_has(title, "Installer")) return &installer_bmp;
    if (title_has(title, "Tutoriel")) return &tutorial_bmp;
    if (title_has(title, "Store")) return &store_bmp;
    if (title_has(title, "À propos") || title_has(title, "A propos")) return &about_bmp;
    return 0;
}

const ui_bitmap_t *ui_bitmap_wallpaper(void) { return 0; }
const ui_bitmap_t *ui_bitmap_start_button(void) { return &start_bmp; }
